INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Core HR & People Directory$q$, $q$Centralized employee records, org charts, and document storage that serve as the single source of truth for people data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Time & Attendance$q$, $q$Time-off requests, approvals, and attendance tracking with configurable policies for different teams and locations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Payroll$q$, $q$Integrated payroll processing available in select regions, connected directly to core HR data to reduce duplicate entry.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Performance Management$q$, $q$Goal tracking, structured review cycles, and 1:1 tools to support ongoing performance conversations.$q$, 3);
