INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Employee Engagement Surveys$q$, $q$Pulse and lifecycle surveys to measure sentiment and track engagement trends over time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Onboarding & Offboarding Workflows$q$, $q$Automated, no-code workflows that guide new hires through onboarding tasks and manage employee exits.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$People Analytics$q$, $q$Dashboards and reporting on headcount, turnover, DEI, and engagement metrics to support data-driven HR decisions.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Social Home Feed$q$, $q$A customizable news feed highlighting shout-outs, milestones, and company updates to drive employee engagement.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Mobile Apps$q$, $q$Native iOS and Android apps giving employees self-service access to HR tasks from anywhere.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Modern, engaging interface that feels less transactional than traditional HR software$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Broad coverage of core HR, performance, compensation, and engagement in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Highly configurable no-code workflows that reduce reliance on IT or developers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Strong fit for distributed and hybrid teams across multiple locations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Modular structure lets companies add payroll or other modules as they grow$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Pricing is not published and requires a custom quote, making upfront budgeting harder$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Payroll coverage is limited to select regions, so multinational payroll may need separate tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Initial setup and configuration can require meaningful time investment$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$May be more platform than very small teams need, both in cost and complexity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Some advanced modules add incremental cost on top of the core platform$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$What is Bob by HiBob?$q$, $q$Bob is a cloud-based HR platform from HiBob that combines core HR, payroll, performance, compensation, and employee engagement tools in a single, configurable system.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$How much does HiBob cost?$q$, $q$HiBob does not publish fixed pricing tiers. Cost is quote-based, typically priced per employee per month and dependent on company size and the modules selected.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Does HiBob offer a free trial?$q$, $q$HiBob does not publicly advertise a self-serve free trial; prospective customers typically request a demo and custom quote from the sales team.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Is HiBob suitable for small businesses?$q$, $q$HiBob can work for smaller companies, but it is primarily designed for mid-sized and fast-growing organizations, so very small teams may find simpler or lower-cost tools sufficient.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Does Bob include payroll?$q$, $q$Yes, Bob offers payroll as a module, but availability is limited to select regions, so companies with complex multinational payroll needs may require additional or specialized solutions.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Consolidating core HR for a scaling company$q$, $q$Replacing spreadsheets and disconnected tools with a single system for employee records, time off, and onboarding as headcount grows.$q$, $q$HR and People Ops teams at mid-sized, fast-growing companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Managing performance and compensation cycles$q$, $q$Running structured review cycles, tracking goals, and planning compensation decisions within the same platform used for core HR.$q$, $q$People leaders and managers overseeing performance and pay$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Supporting distributed and hybrid teams$q$, $q$Giving employees across multiple offices and time zones self-service access to HR data, requests, and company updates.$q$, $q$Companies with remote, hybrid, or multi-location workforces$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Automating routine HR workflows$q$, $q$Using no-code workflow builders to automate onboarding tasks, approvals, and other repetitive HR processes without developer support.$q$, $q$HR administrators looking to reduce manual admin work$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Core HR$q$, $q$Custom pricing$q$, $q$Custom/Annual contract$q$, $q$["Employee directory and org charts","Time-off and attendance tracking","Onboarding and offboarding workflows","Employee self-service"]$q$::jsonb, 0);
