INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Performance & Compensation$q$, $q$Custom pricing$q$, $q$Custom/Annual contract$q$, $q$["Goal tracking and review cycles","Compensation planning and benchmarking","Manager and employee performance tools","People analytics dashboards"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Full Suite / Enterprise$q$, $q$Custom pricing$q$, $q$Custom/Annual contract$q$, $q$["All core, payroll, performance, and compensation modules","Employee engagement surveys","Advanced workflow automation","Dedicated implementation and support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HiBob builds Bob, a cloud-based human resources platform designed to help modern, fast-growing companies manage the full employee lifecycle from a single system. Rather than bolting HR onto spreadsheets or legacy enterprise suites, Bob centralizes people data, workflows, and communication in one configurable hub that HR teams and employees actually want to use.$q$, $q$At its core, Bob covers the essentials of core HR: employee records, org charts, time-off tracking, and onboarding, then extends into payroll (in supported regions), performance management, compensation planning, and employee engagement surveys. The platform is built around a customizable home feed and people directory that gives it a more social, consumer-app feel than typical HRIS software.$q$, $q$HiBob positions Bob for mid-market and scaling companies, particularly those with distributed or hybrid teams, rather than very small startups or the largest global enterprises. Its emphasis on configurability, automation (via no-code workflows), and analytics has made it a common choice for HR and People teams that want a single system of record without heavy IT overhead.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$who-bob-is-for$q$, $q$Who Bob Is For$q$, 2, ARRAY[$q$Bob is aimed squarely at mid-sized and scaling companies, generally somewhere between roughly 100 and a few thousand employees, that have outgrown spreadsheets and point solutions but don't need the full complexity of a legacy enterprise HR suite. Fast-growing tech, professional services, and other knowledge-work companies are a natural fit.$q$, $q$Organizations with distributed, hybrid, or multi-country workforces tend to get the most value from Bob, since the platform is built around consolidating people data and processes for teams spread across offices and time zones. HR and People Ops leaders who want strong self-service, automation of routine HR workflows, and a modern employee experience are the primary buyers.$q$, $q$Bob also suits companies that plan to grow their HR tech stack over time, since it is modular: teams can start with core HR and add payroll, performance, or compensation modules as needs evolve. Businesses that value a highly configurable, visually modern interface over a bare-bones, purely transactional HRIS will find Bob's approach appealing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small businesses and early-stage startups with only a handful of employees may find Bob more platform than they need, both in terms of cost and configuration overhead, when a simpler or free HR tool would suffice for basic tasks like time-off tracking.$q$, $q$Companies that need publicly listed, self-serve pricing and want to avoid a sales-led buying process may be frustrated, since HiBob does not publish fixed price tiers and instead requires a custom quote based on headcount and modules selected, which can slow down evaluation.$q$, $q$Large multinational enterprises with highly complex, deeply entrenched payroll and compliance requirements across many countries, or organizations already heavily invested in a legacy HRIS like Workday or SAP SuccessFactors, may find switching costs and the scope of Bob's payroll coverage a limiting factor compared to more specialized global payroll or enterprise ERP-HR suites.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Bob's foundation is core HR: a centralized employee directory, org chart, document management, and time-off and attendance tracking, all designed with self-service in mind so employees and managers can handle routine requests without going through HR for every action.$q$, $q$Beyond the basics, Bob offers performance management (reviews, goals, and 1:1 tracking), compensation management for planning and benchmarking pay, and payroll in select regions, letting companies consolidate more of the employee lifecycle into one system rather than stitching together separate point tools.$q$, $q$The platform also includes employee engagement surveys and pulse feedback, onboarding and offboarding workflows, no-code workflow automation for routine HR processes, and people analytics dashboards, giving HR teams visibility into headcount, turnover, and engagement trends alongside the operational tools they use day to day.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$the-bob-experience$q$, $q$The Bob Experience$q$, 2, ARRAY[$q$Using Bob feels closer to a social or consumer app than a traditional enterprise HR system. A customizable home feed surfaces birthdays, work anniversaries, shout-outs, and company announcements, which is intended to make the platform something employees check regularly rather than only when they need to file a request.$q$, $q$For HR administrators, the experience centers on configurability: workflows, forms, and approval chains can be built without code, and the interface can be tailored to reflect company branding and structure. Native mobile apps extend that experience to employees who are on the go or don't sit at a desk.$q$, $q$Overall, the day-to-day experience emphasizes transparency and self-service, employees can see their own data, request time off, and complete reviews directly in the app, while HR teams get automation and reporting to reduce manual admin. The tradeoff for that configurability is a setup and implementation phase that typically involves HiBob's team to properly configure workflows and, where applicable, payroll.$q$]::text[], 4);
