INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Templates gallery$q$, $q$Start new projects faster with a library of pre-built templates for common workflows and industries.$q$, 8);
