INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Premium modules like proofing, resourcing, and analytics can add cost beyond the base plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Breadth of views and modules creates a learning curve for new teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Advanced enterprise governance and permission controls are less deep than dedicated enterprise suites$q$, 2);
