INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Employee Scheduling$q$, $q$Drag-and-drop schedule builder with reusable templates, shift-swap requests, and auto-scheduling to speed up weekly planning.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Time Clock & Time Tracking$q$, $q$GPS-enabled mobile clock-in, POS/tablet terminal, or web clock-in, with alerts for late arrivals and approaching overtime.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Team Communication$q$, $q$Built-in messaging and group chat so managers can send shift updates and announcements without a separate text thread.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Hiring & Onboarding$q$, $q$Post open roles to major job boards, track applicants, and handle new-hire paperwork digitally.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Integrated Payroll$q$, $q$An add-on payroll service that runs directly off tracked hours, reducing manual re-entry between time clock and pay run.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Labor Cost Management$q$, $q$Dashboards that compare scheduled and actual labor hours against sales to help control costs in real time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$PTO & Time-Off Management$q$, $q$Policy-based paid time off tracking with employee-submitted requests and manager approvals.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$HR & Compliance Tools$q$, $q$Document storage and labor-law compliance guidance aimed at small-business HR basics.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$POS Integrations$q$, $q$Connections with point-of-sale providers such as Square, Clover, and Toast to align labor data with sales.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Mobile Apps$q$, $q$Native iOS and Android apps giving managers and employees access to scheduling, messaging, and the time clock on the go.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Free plan covers core scheduling and time tracking for a single location$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Scheduling, time tracking, messaging, and payroll are integrated rather than separate tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$GPS-enabled time clock and overtime alerts help control attendance issues and labor costs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$POS integrations tie labor data directly to sales for real-time cost tracking$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Purpose-built for hourly, shift-based teams rather than generic office HR$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Free plan is limited to one location and a capped number of employees$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Payroll and some add-ons (tip management, task management) carry extra fees on top of the base subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Not designed for salaried, remote, or non-shift-based workforces$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$HR and compliance features are basic compared to dedicated enterprise HCM platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Multi-location pricing can add up as a business grows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Is Homebase free to use?$q$, $q$Homebase offers a free plan that includes basic scheduling and time tracking for a single location with a capped number of employees. Paid plans remove the employee cap and add features like hiring, PTO management, and labor-cost tools.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Does Homebase include payroll?$q$, $q$Payroll is available as an add-on rather than being bundled into every plan by default. It runs off the hours already tracked in the app, which reduces manual data entry when running payroll.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$What industries use Homebase?$q$, $q$Homebase is primarily used by restaurants, retail stores, salons, gyms, and other small businesses that schedule hourly, shift-based employees rather than salaried office staff.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Does Homebase integrate with point-of-sale systems?$q$, $q$Yes. Homebase integrates with several POS providers, including Square, Clover, and Toast, allowing labor data to be compared against sales in real time.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Is there a mobile app for employees?$q$, $q$Yes, Homebase has native iOS and Android apps that let employees view schedules, request shift swaps or time off, clock in and out, and message their team from a phone.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Weekly Shift Scheduling$q$, $q$A restaurant or retail manager builds and publishes next week's shift schedule from a template, and staff view it and request swaps from their phones.$q$, $q$Restaurant and retail shift managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$GPS Time Tracking$q$, $q$Employees clock in and out via a mobile app with location checks, reducing buddy-punching and giving managers accurate attendance records.$q$, $q$Small business owners tracking hourly attendance$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Payroll Tied to Hours Worked$q$, $q$A business runs payroll directly from tracked time-clock hours through the payroll add-on, cutting down on manual reconciliation.$q$, $q$Owner-operators handling their own payroll$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Hiring and Onboarding New Staff$q$, $q$A growing shop posts an open role to job boards, screens applicants, and completes new-hire paperwork digitally before the first shift.$q$, $q$Hiring managers at small hourly-workforce businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, $q$["Single location, capped employee count","Basic scheduling and time tracking","Team messaging","POS integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Essentials$q$, $q$$24/month per location$q$, $q$monthly (annual billing discount available)$q$, $q$["Unlimited employees","Advanced scheduling tools","Team communication","Time clock with GPS tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Plus$q$, $q$$56/month per location$q$, $q$monthly (annual billing discount available)$q$, $q$["Hiring and applicant tracking","PTO policy controls","Departments and permissions","Everything in Essentials"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$All-in-one$q$, $q$$96/month per location$q$, $q$monthly (annual billing discount available)$q$, $q$["New-hire onboarding","Labor cost management dashboards","HR compliance tools","Everything in Plus"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Homebase is workforce management software built specifically for hourly, shift-based teams — the restaurants, retail shops, salons, and small service businesses that run on rotating schedules rather than nine-to-five desks. Rather than bundling generic HR features into a one-size-fits-all suite, Homebase focuses on the day-to-day mechanics of running an hourly workforce: building the schedule, tracking who actually showed up, paying people accurately, and keeping the team in sync without a group text chain.$q$, $q$The product is organized around a free core (scheduling and time tracking for a single location with a modest employee cap) with paid tiers that unlock unlimited employees, hiring and onboarding tools, PTO management, and deeper labor-cost controls. Payroll runs as an add-on that pulls directly from tracked hours, which is one of the app's more distinctive integrations — it removes a manual step that many competing scheduling tools leave to a separate system.$q$, $q$Homebase ties its scheduling and time clock data together with point-of-sale integrations (Square, Clover, Toast, and others), so labor costs can be measured against real-time sales rather than reconciled after the fact. The result is a tool aimed less at enterprise HR departments and more at owner-operators and shift managers who need scheduling, attendance, and payroll to work together out of the box.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$who-its-for$q$, $q$Who Homebase Is For$q$, 2, ARRAY[$q$Homebase is built for small and mid-sized businesses that schedule hourly employees across shifts — restaurants, cafes, retail stores, salons, gyms, and similar service operations. Owners running one or a handful of locations, where a manager needs to build next week's schedule, track clock-ins, and message the team from one place, are the core audience.$q$, $q$It also suits businesses that want scheduling, time tracking, and payroll to live under one roof instead of stitching together separate tools. Because payroll and HR add-ons sit on top of the same time data, owners who are currently reconciling spreadsheets, a separate time clock, and a third-party payroll provider can consolidate several workflows into one subscription.$q$, $q$Franchise operators and multi-location small chains that need consistent scheduling templates and labor-cost visibility across sites are another good fit, since the per-location pricing model scales predictably as a business adds new stores.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Homebase is not built for salaried, office-based, or fully remote knowledge-work teams — its scheduling grid, shift-swap tools, and GPS time clock are optimized for in-person shift work, so companies without hourly, on-site staff will find most of the feature set irrelevant.$q$, $q$Large enterprises with complex HRIS, benefits administration, or multi-country payroll needs will likely outgrow Homebase quickly; its HR and compliance tools are aimed at small-business basics rather than the depth offered by dedicated enterprise HCM platforms.$q$, $q$Businesses that need the full feature set (hiring, PTO, HR tools, labor-cost management) but are very cost-sensitive should budget carefully — the free plan is limited to a single location and a capped headcount, and the useful add-ons like payroll and tip management carry additional per-employee or flat monthly fees on top of the base subscription.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Homebase offers a drag-and-drop schedule builder with templates, shift-swap and time-off requests, and auto-scheduling to speed up weekly planning. This pairs with a time clock that supports mobile GPS clock-in, a tablet/POS terminal, or a web browser, plus overtime and late-clock-in alerts to keep labor costs in check.$q$, $q$Beyond scheduling and time tracking, Homebase layers in team messaging for shift updates and announcements, hiring tools that post open roles to major job boards and track applicants, and digital onboarding for new-hire paperwork. Paid tiers add PTO policy management, HR document storage and compliance guidance, and labor-cost dashboards that compare scheduled hours against sales in real time.$q$, $q$Payroll is available as an add-on that runs directly off tracked hours, reducing manual re-entry between the schedule, the time clock, and the pay run. POS integrations with providers like Square, Clover, and Toast let sales and labor data flow together, and native iOS and Android apps give both managers and employees access to schedules, messaging, and time clock functions from their phones.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$the-homebase-experience$q$, $q$The Homebase Experience$q$, 2, ARRAY[$q$Day to day, Homebase centers on a schedule view that a manager builds once and can copy forward as a template, with employees able to view shifts, request swaps, and request time off from their phones. Notifications and in-app messaging cut down on the back-and-forth that typically happens over text or a printed schedule taped to a break-room wall.$q$, $q$The time clock experience is designed to prevent common attendance headaches: GPS location checks discourage buddy-punching, and automatic alerts flag when someone clocks in late or is approaching overtime, giving managers a chance to intervene before it affects payroll. Because the same hours feed straight into the payroll add-on, the pay run itself requires less manual reconciliation than tools where scheduling and payroll are disconnected.$q$, $q$Overall, users tend to describe the experience as straightforward and operationally focused rather than feature-bloated — the interface prioritizes the handful of tasks a shift manager does every day (build the schedule, approve a swap, check who's clocked in, message the team) over deep customization or enterprise-style configuration.$q$]::text[], 4);
