INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Heatmaps$q$, $q$Click, tap, move, and scroll heatmaps visualize where visitors focus attention and interact most on a page.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Session Recordings$q$, $q$Anonymized playback of real visitor sessions, with automatic flags for rage clicks, dead clicks, and u-turns.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$On-Site Surveys$q$, $q$Behavior-triggered surveys collect NPS, CSAT, and open-text feedback directly on the page without redirecting users.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Feedback Widget$q$, $q$Lets visitors highlight specific page elements and leave contextual comments about confusing or broken UX.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Funnels$q$, $q$Basic conversion funnel tracking highlights where users drop off across a multi-step flow.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Filters and Segmentation$q$, $q$Narrow heatmaps and recordings by device, traffic source, URL, or custom visitor attributes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Integrations$q$, $q$Connects with tools such as Slack, Google Analytics, Jira, and Zapier to route insights into existing workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Developer API and Tracking Snippet$q$, $q$A lightweight JavaScript snippet plus API access make installation and custom data handling straightforward for engineering teams.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Survey and Feedback Templates$q$, $q$Pre-built templates speed up creating common research instruments like NPS, PMF, and post-purchase surveys.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Visual heatmaps and recordings make user behavior easy to understand without technical analytics training$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Genuine free plan makes it accessible for small sites and early-stage teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Fast setup with a single tracking snippet and minimal configuration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Combines quantitative-adjacent behavior data with qualitative survey and feedback tools in one place$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Widely used and well documented, with strong integration support for common marketing and dev tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Daily session caps on lower plans mean data accumulates slowly for high-traffic or lower-tier accounts$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Not a substitute for full quantitative analytics platforms with deep attribution or event querying$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Session recording raises privacy and consent considerations that require careful configuration$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Ongoing integration into Contentsquare has introduced branding and plan changes that can confuse existing users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Advanced features and larger session volumes require moving up to higher-cost tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$What does Hotjar actually do?$q$, $q$Hotjar captures how visitors interact with a website through heatmaps, session recordings, on-site surveys, and feedback widgets, giving teams a visual, qualitative view of user behavior alongside standard analytics.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Is Hotjar free to use?$q$, $q$Hotjar has historically offered a free plan with a capped number of daily sessions for heatmaps and recordings, making it usable for smaller sites before upgrading to a paid tier for higher volume and more features.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Is Hotjar still a standalone product?$q$, $q$Hotjar was acquired by Contentsquare in 2021 and formally merged into the Contentsquare group in 2025. Its heatmap, recording, and survey tools continue to operate but are increasingly integrated into the broader Contentsquare platform.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Does Hotjar replace Google Analytics?$q$, $q$No. Hotjar is designed to complement quantitative analytics tools by adding qualitative context, such as recordings and heatmaps, rather than replacing detailed traffic and attribution reporting.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Is Hotjar GDPR-friendly and privacy safe?$q$, $q$Hotjar includes settings to mask sensitive form fields and text in recordings and offers privacy controls, but teams are responsible for configuring these correctly and reviewing consent requirements for their jurisdiction.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Diagnosing checkout or signup drop-off$q$, $q$Teams use session recordings and funnels to watch where users hesitate or abandon a multi-step checkout or signup flow, identifying friction that conversion metrics alone don't explain.$q$, $q$E-commerce and SaaS conversion optimization teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Validating a redesign before and after launch$q$, $q$Heatmaps captured before and after a landing page redesign show whether new layouts direct attention to key calls-to-action as intended.$q$, $q$UX designers and product marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Collecting in-context qualitative feedback$q$, $q$Behavior-triggered surveys and feedback widgets gather visitor sentiment and open-text comments at the moment of interaction, surfacing usability issues directly from users.$q$, $q$UX researchers and customer experience teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Building a visual case for stakeholders$q$, $q$Agencies and internal teams use recordings and heatmap screenshots as evidence in UX audit reports or stakeholder presentations to justify proposed changes.$q$, $q$Agencies and consultants running UX audits$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Basic (Free)$q$, $q$Free$q$, $q$N/A$q$, $q$["Up to 35 daily sessions for heatmaps and recordings","Basic on-site surveys","Feedback widget","Core heatmap and recording tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Plus$q$, $q$From around $39/month$q$, $q$Monthly or annual (annual billing at a discount)$q$, $q$["Higher daily session cap for heatmaps and recordings","More survey and feedback capacity","Additional filtering options","Priority support over the free tier"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Business$q$, $q$From around $99/month$q$, $q$Monthly or annual (annual billing at a discount)$q$, $q$["Higher session volume than Plus","Expanded integrations","Advanced filtering and segmentation","Funnels and additional reporting tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Scale$q$, $q$Custom/higher-volume pricing$q$, $q$Monthly or annual, often quote-based at scale$q$, $q$["Highest self-serve session volume","Enterprise-oriented features and support","Advanced access controls","Suited to larger sites and organizations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hotjar is a behavior analytics platform that helps website owners see beyond traditional pageview and conversion metrics by showing what visitors actually do on a page. Founded in 2014 and headquartered in St. Julian's, Malta, the company built its reputation on a simple idea: numbers tell you what happened, but heatmaps and recordings tell you why. A lightweight tracking script captures clicks, taps, scrolling, and mouse movement, then turns that raw activity into visual reports non-technical teams can read at a glance.$q$, $q$The product suite centers on four pillars: heatmaps that visualize where attention and interaction concentrate on a page, session recordings that replay individual visitor journeys, on-site surveys that collect direct feedback in context, and feedback widgets that let users flag confusing or broken elements as they browse. Together these tools give product, marketing, and UX teams a qualitative layer that complements analytics platforms like Google Analytics or Mixpanel rather than replacing them.$q$, $q$In 2021 Hotjar was acquired by Contentsquare, a larger digital experience analytics company, and the two brands operated in parallel for several years before Hotjar formally merged into the Contentsquare group in 2025. Hotjar's core tools now live inside the Contentsquare platform, continuing to serve the same use case of turning on-site behavior into actionable UX and conversion insight, while benefiting from Contentsquare's broader analytics and AI capabilities.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$who-for$q$, $q$Who Hotjar Is For$q$, 2, ARRAY[$q$Hotjar is best suited to product managers, UX researchers, and conversion rate optimization specialists who need visual, qualitative evidence to back up or challenge what quantitative analytics is telling them. Teams running A/B tests or redesigns often use Hotjar to understand why a variant underperformed or why users abandon a checkout flow, since heatmaps and recordings can surface friction points that click-through rates alone cannot explain.$q$, $q$Marketing teams and small-to-midsize SaaS or e-commerce businesses also get strong value from Hotjar, particularly through its free tier, which makes it accessible to founders and solo marketers who want to watch real user sessions before investing in a full analytics stack. Agencies running UX audits for clients frequently rely on Hotjar's recordings and heatmaps as a fast way to build a visual case for recommended changes.$q$, $q$Larger organizations already invested in digital experience analytics, or those needing enterprise-grade session volume and integrations, are a natural fit as well, especially since Hotjar's tooling is now part of the broader Contentsquare platform aimed at enterprise experience optimization teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$who-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Hotjar is not a full replacement for a quantitative web analytics platform. Teams that need deep multi-touch attribution, detailed funnel reporting across long customer lifecycles, or granular event-level querying will still need a tool like Google Analytics, Mixpanel, or Amplitude alongside it, and expecting Hotjar to serve as a sole analytics solution will lead to disappointment.$q$, $q$Sites with very low traffic may find limited value in the free and lower tiers, since daily session caps mean heatmaps and recordings can take a long time to accumulate a statistically meaningful sample. Similarly, teams with strict data-minimization or privacy requirements should carefully review session recording and PII-masking settings before rolling the tool out, as recording real user sessions raises consent and compliance considerations that not every organization is prepared to manage.$q$, $q$Businesses that already use Contentsquare's full enterprise suite may find the standalone Hotjar branding and plans less relevant going forward, since functionality is consolidating under the parent platform; buyers evaluating new tooling today should confirm current plan names and packaging before assuming legacy Hotjar pricing still applies.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Hotjar offers click, move, and scroll heatmaps that aggregate visitor interaction across a page into an easy-to-read visual overlay, helping teams spot ignored calls-to-action or content that gets more attention than expected. Session recordings complement this by letting teams watch anonymized playback of individual visits, with filters for rage clicks, dead clicks, and u-turns that flag likely moments of user frustration automatically.$q$, $q$On-site surveys and feedback widgets round out the qualitative side, letting teams trigger targeted questions based on behavior such as exit intent, time on page, or scroll depth, and collect open-text, NPS, or CSAT-style responses without visitors leaving the page. A feedback widget lets users highlight a specific element and leave a comment, which is especially useful for beta launches or redesign feedback.$q$, $q$Supporting features include basic conversion funnels for spotting drop-off between steps, filtering and segmentation so teams can narrow heatmaps or recordings to a specific device, source, or user segment, and integrations with tools such as Slack, Google Analytics, Jira, and Zapier so insights can flow into existing workflows. A JavaScript-based tracking snippet and API access make the platform straightforward to install and extend for developers.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$experience$q$, $q$The Hotjar Experience$q$, 2, ARRAY[$q$Setting up Hotjar typically takes only a few minutes: install a single tracking snippet, choose which pages to monitor, and heatmap or recording data begins accumulating almost immediately. The dashboard is designed for non-technical users, presenting visual overlays and filterable recording lists rather than raw event tables, which is part of why the product became popular with marketers and designers as well as engineers.$q$, $q$Day-to-day use tends to revolve around watching a handful of flagged recordings after a release, checking a heatmap after a landing-page redesign, or reviewing survey responses that came in overnight. Many teams pair Hotjar with their existing analytics stack, using quantitative tools to spot where a problem is happening and Hotjar to understand why, closing the loop between metrics and lived user experience.$q$, $q$Since becoming part of Contentsquare, the day-to-day workflow for existing users has shifted gradually as tools are consolidated into the broader platform, with billing, account management, and some features moving under the Contentsquare umbrella. New evaluators should expect to encounter Hotjar's tools presented alongside, or integrated into, Contentsquare's wider experience analytics and voice-of-customer offerings rather than as a fully separate standalone product.$q$]::text[], 4);
