INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Multiple survey formats$q$, $q$Deploy surveys as popovers, expandable buttons, embedded inline blocks, chat-style bubbles, full-screen modals, or standalone links shared outside the website.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Ready-made templates$q$, $q$Launch with expert-built templates for NPS, CSAT, product-market fit, and exit-intent feedback instead of writing questions from scratch.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Varied question types$q$, $q$Mix rating scales, NPS scores, multiple choice, checkboxes, open-text, and statement-only prompts within a single survey.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Behavioral and page targeting$q$, $q$Trigger surveys by specific URL, time on page, scroll depth, exit intent, or device type so feedback requests appear at relevant moments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Link surveys$q$, $q$Host a survey on its own URL and distribute it via email, social media, or in-app messages when an on-page widget isn't the right fit.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Brand customization$q$, $q$Match survey widgets to brand colors and add a company logo without any code changes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$AI-assisted response analysis$q$, $q$Summarize themes and sentiment across open-text answers so teams don't have to read every response individually.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$NPS tracking$q$, $q$Run a standing Net Promoter Score survey and monitor the rolling score over recent periods.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Third-party integrations$q$, $q$Send survey responses to tools such as Slack, HubSpot, and Salesforce to plug feedback into existing workflows.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$No-code setup lets non-technical teams launch a survey in minutes using an existing template$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Multiple delivery formats (popover, button, embedded, link) suit different pages and use cases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Precise targeting by URL, behavior, or exit intent surfaces feedback at meaningful moments$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$AI-assisted analysis reduces the manual effort of reading large volumes of open-text responses$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Shares an account and data model with Hotjar's/Contentsquare's behavioral analytics for teams already using those tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Now billed as a separate Voice of Customer product from Hotjar's heatmap and recording plans, adding cost for teams that want both$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Free-tier response allowance is limited, so active feedback programs quickly require a paid plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Lacks the advanced sampling, panel, and statistical tooling of dedicated enterprise survey platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Branching logic and question flow are simpler than what full-featured survey builders offer$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Best suited to web-based feedback; not designed for offline or non-web survey channels$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$What is Hotjar Surveys used for?$q$, $q$It's used to collect direct, qualitative feedback from website visitors through on-page widgets or shareable survey links, covering use cases like NPS, customer satisfaction, product-market fit, and exit-intent research.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Is Hotjar Surveys free?$q$, $q$There is a free plan that includes a limited number of survey responses per month and a small number of concurrent surveys; higher response volumes and advanced features require a paid Voice of Customer plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$How is Hotjar Surveys priced compared to Hotjar's heatmaps and recordings?$q$, $q$Since Hotjar's product lines were unified under Contentsquare, surveys are billed as part of the Voice of Customer product, separately from the Observe plans that cover heatmaps and session recordings.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$What types of surveys can I create?$q$, $q$You can build popover, button, embedded, bubble, full-screen, and link surveys, using question types like rating scales, NPS, multiple choice, checkboxes, and open text, or start from a ready-made template.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Does Hotjar Surveys require a developer to set up?$q$, $q$No. Once the Hotjar tracking snippet is installed on a site, surveys can be built, styled, and targeted entirely through the no-code, browser-based editor.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Post-purchase and checkout feedback$q$, $q$Trigger a short survey immediately after checkout or on cart-abandonment to learn why visitors did or didn't complete a purchase.$q$, $q$Ecommerce and growth marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Feature validation$q$, $q$Place an embedded or popover survey on a new feature page to gather quick reactions before investing further in development.$q$, $q$Product managers and UX researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Ongoing NPS tracking$q$, $q$Run a standing NPS survey to monitor customer loyalty trends over time and flag drops that need investigation.$q$, $q$Customer success and product leadership$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Off-site feedback collection$q$, $q$Share a link survey through email or social channels to collect feedback from customers who aren't currently on the website.$q$, $q$Marketing and customer research teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["Limited monthly survey responses","A small number of concurrent surveys","Core survey formats and question types","Access to standard templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Growth (Voice of Customer)$q$, $q$From $99/month$q$, $q$monthly$q$, $q$["500 survey responses per month, scaling with usage","Advanced targeting and filtering","AI-assisted open-text analysis","Custom branding on surveys","Third-party integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, $q$["High-volume response allowances","Advanced administration and security controls","Priority support and onboarding","Expanded integration options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hotjar Surveys is the feedback-collection module of the Hotjar platform, reachable at hotjar.com/surveys, and now sold as part of Contentsquare following the two companies' 2021 merger and 2025 product unification. Where Hotjar's heatmaps and session recordings show what visitors do on a page, Surveys is built to answer the harder question of why they do it, by asking website visitors directly through on-page widgets or a standalone link.$q$, $q$The product lets teams launch surveys in several formats: a popover that slides in at the bottom of a page, a persistent button that expands into a full survey, an embedded block that sits inline with page content, a chat-style bubble, a full-screen modal, or a link survey hosted on its own URL for sharing over email, social, or in-app messages. Expert-built templates cover common research jobs such as Net Promoter Score, customer satisfaction, product-market fit, and exit-intent feedback, so teams can launch a first survey without writing questions from scratch.$q$, $q$Surveys sits alongside Hotjar's Observe (heatmaps, recordings) and Engage (user interview recruiting) tools, and under Contentsquare's current packaging it is billed as part of the Voice of Customer line rather than bundled automatically with heatmap and recording plans. That makes it best understood as a dedicated qualitative-feedback layer that a team adds on top of, or instead of, Hotjar's behavioral analytics products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$who-hotjar-surveys-is-for$q$, $q$Who Hotjar Surveys Is For$q$, 2, ARRAY[$q$Product managers and UX researchers who need to validate a hypothesis quickly are a natural fit. Rather than commissioning a formal research study, a PM can drop a targeted popover survey on a specific page or user flow, ask two or three focused questions, and get directional feedback within days instead of weeks.$q$, $q$Marketing and conversion-optimization teams also lean on the tool heavily, using post-purchase, cart-abandonment, or exit-intent surveys to understand friction points in checkout and onboarding flows. Because surveys can be triggered by URL, behavior, or device, ecommerce and SaaS marketers can target the exact moment a visitor's intent is most legible.$q$, $q$Startups and small-to-mid-size teams that want a lightweight, no-code way to hear from customers without adopting a heavyweight enterprise research suite are well served here, especially if they are already using Hotjar (or Contentsquare) for behavioral analytics and want feedback data living in the same account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need rigorous, statistically representative market research, panel management, or academic-grade survey methodology are better served by dedicated research platforms such as Qualtrics or SurveyMonkey's enterprise tiers, which offer deeper sampling, weighting, and analysis controls than an on-site feedback widget is designed for. Hotjar Surveys optimizes for speed and simplicity, not methodological rigor.$q$, $q$Teams hoping to get surveys included for free alongside heatmaps and recordings should note that, since the Contentsquare unification, Voice of Customer (surveys) is billed as its own product line separate from the Observe (analytics) plans, so budgeting for a single low-cost bundle is no longer realistic once usage grows beyond the free response allowance. Anyone comparing total cost of ownership across both products should size that unbundled pricing into the decision up front.$q$, $q$Teams that need complex branching logic, multi-channel offline distribution, or survey programs spanning many non-web channels (call centers, kiosks, print) will find the tool's scope — on-site and link-based web surveys — too narrow for their needs. Highly regulated industries that require custom consent flows or long, multi-page questionnaires may also outgrow the format quickly.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Surveys can be delivered as popovers, buttons, embedded blocks, chat-style bubbles, full-screen modals, or shareable links, giving teams flexibility over how intrusive or prominent the ask feels relative to the page experience. Choosing the right format lets a team balance response volume against how disruptive the prompt feels to visitors mid-task.$q$, $q$A library of question types — rating scales, NPS, multiple choice, checkboxes, open text, and statement-only prompts — pairs with ready-made templates for NPS, CSAT, PMF, and exit surveys, so most teams can launch with an established template and adjust wording rather than designing a survey from a blank page. Templates are built around industry-standard phrasing, which keeps scores like NPS comparable across companies and time periods.$q$, $q$Targeting rules let surveys trigger by URL, time on page, scroll depth, exit intent, or device, while response dashboards support filtering, sentiment read-outs, and AI-assisted analysis of open-text answers; native integrations pass responses into tools like Slack, HubSpot, and Salesforce for downstream workflows. Together, these controls let a single survey serve both a quick pulse-check and a more deliberate, segmented research effort.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$the-hotjar-surveys-experience$q$, $q$The Hotjar Surveys Experience$q$, 2, ARRAY[$q$Setting up a survey is a no-code, WYSIWYG process: pick a template or start blank, arrange questions, set the display style and targeting rules, and match the widget's colors and logo to brand guidelines, all inside the browser-based editor without needing a developer beyond the one-time tracking snippet install. Most first surveys can go live within a single working session.$q$, $q$Once live, responses populate a dashboard where teams can read individual answers, track an NPS score trend over the last 30 days, filter by device or segment, and lean on AI-assisted summarization to spot themes across open-text responses instead of reading every reply manually. Recurring surveys build up a longitudinal view of sentiment that's useful for spotting regressions after a redesign or release.$q$, $q$The overall experience is intentionally lightweight and self-serve, which is its main strength for fast-moving teams and its main limitation for anyone expecting the depth of a full research suite; it works best as a quick, always-on feedback channel that complements — rather than replaces — deeper qualitative research methods. Teams already inside the Hotjar or Contentsquare ecosystem will find the workflow familiar, since survey targeting and analysis echo patterns used elsewhere in the platform.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
