INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Scheduling and dispatch$q$, $q$Drag-and-drop calendar and technician assignment tools let office staff schedule and dispatch jobs to the right crew based on availability and location.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Online booking$q$, $q$A customer-facing booking widget lets clients request and schedule appointments directly, reducing phone calls and manual scheduling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Invoicing and estimates$q$, $q$Create and send professional estimates and invoices from the office or in the field, with digital customer approval and signature capture.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Payment processing$q$, $q$Accept card and digital payments on-site or online, with transactions automatically reconciled against the corresponding job and invoice.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$GPS tracking$q$, $q$Track technician locations and routes in real time to improve dispatch decisions and provide accurate arrival estimates to customers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$QuickBooks integration$q$, $q$Two-way sync with QuickBooks Online keeps invoices, payments, and customer records aligned with company bookkeeping.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Customer relationship management$q$, $q$Centralized customer profiles store job history, notes, and communications so any team member can see the full relationship at a glance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Marketing automation$q$, $q$Automated review requests, email campaigns, and postcard marketing help businesses generate repeat and referral business.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Reporting and analytics$q$, $q$Dashboards surface revenue trends, technician performance, and job profitability to support day-to-day and long-term business decisions.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Mobile app for technicians$q$, $q$Field technicians can view job details, update statuses, capture photos, and collect payment directly from a dedicated mobile app.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$All-in-one platform covering scheduling, invoicing, payments, and CRM for home service businesses$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Mobile app gives field technicians real-time access to job details and payment collection$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Strong integration with QuickBooks Online simplifies bookkeeping$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Online booking and automated marketing tools help generate and retain customers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Reporting dashboards give owners visibility into revenue and technician performance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Per-user pricing and optional add-ons can increase monthly cost as a team grows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Advanced features like open API access are reserved for higher-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$May offer more functionality than very small, single-technician operations need$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Payment processing fees apply on top of the subscription cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Less suited to businesses running long, multi-phase projects rather than dispatched service jobs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$What is Housecall Pro used for?$q$, $q$Housecall Pro is field service management software used by home service businesses to schedule jobs, dispatch technicians, send estimates and invoices, collect payments, and manage customer relationships from one platform.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$How much does Housecall Pro cost?$q$, $q$Housecall Pro's plans start at $59 per month when billed annually for the Basic tier, with higher tiers such as Essentials and MAX adding more users and features at higher monthly prices.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Does Housecall Pro offer a free trial?$q$, $q$Yes, Housecall Pro offers a free trial period so businesses can evaluate the platform's scheduling, invoicing, and payment features before subscribing.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$What types of businesses use Housecall Pro?$q$, $q$Housecall Pro is used primarily by home service trades such as plumbing, HVAC, electrical, cleaning, pest control, appliance repair, and landscaping companies.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Does Housecall Pro integrate with QuickBooks?$q$, $q$Yes, Housecall Pro offers a two-way integration with QuickBooks Online to sync invoices, payments, and customer data with company bookkeeping.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Scheduling and dispatching multi-crew jobs$q$, $q$Coordinate daily job assignments across multiple technicians and trucks with a shared calendar and real-time status updates.$q$, $q$HVAC and plumbing companies with multiple field crews$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Collecting payment on-site$q$, $q$Let technicians generate invoices and collect card payments directly from the job site, reducing time spent chasing payments later.$q$, $q$Electricians and appliance repair technicians$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Automating customer follow-up and reviews$q$, $q$Send automated review requests and marketing campaigns after job completion to build repeat business and online reputation.$q$, $q$Cleaning and lawn care service businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Replacing paper-based scheduling$q$, $q$Move a growing solo or small-team operation off whiteboards and paper tickets onto a digital scheduling and invoicing system.$q$, $q$Solo operators and small trades businesses scaling up$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Basic$q$, $q$$59/month$q$, $q$Billed annually (monthly billing also available at a higher rate)$q$, $q$["Single user","Scheduling and dispatch","Estimates and invoicing","Online payment collection"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Essentials$q$, $q$$149/month$q$, $q$Billed annually (monthly billing also available at a higher rate)$q$, $q$["Up to 5 users","QuickBooks Online integration","GPS and time tracking","Marketing tools","Zapier integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$MAX$q$, $q$$299/month$q$, $q$Billed annually (monthly billing also available at a higher rate)$q$, $q$["Up to 8 users","Advanced reporting","Open API access","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Housecall Pro is a field service management platform built for home service businesses such as plumbing, HVAC, electrical, cleaning, and lawn care companies. Founded in 2013 and headquartered in Denver, Colorado, the company set out to replace paper job boards, spreadsheets, and whiteboards with a single digital system for running a service business.$q$, $q$At its core, Housecall Pro combines scheduling and dispatch, customer relationship management, estimating, invoicing, and payment processing into one cloud-based product with companion mobile apps for technicians in the field. The goal is to give owners and office staff a real-time view of jobs, crews, and cash flow without juggling multiple disconnected tools.$q$, $q$Over time the platform has expanded well beyond basic scheduling, adding online booking, marketing automation, price book management, and accounting integrations like QuickBooks. It has positioned itself as an end-to-end operating system for small and mid-sized home service companies rather than a narrow point solution.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$who-housecall-pro-is-for$q$, $q$Who Housecall Pro Is For$q$, 2, ARRAY[$q$Housecall Pro is aimed squarely at small and mid-sized home service businesses, from solo owner-operators to companies running multiple crews and trucks. It suits teams that need to coordinate jobs across several technicians while keeping office staff, dispatchers, and field workers on the same page in real time.$q$, $q$The platform is especially well suited to trades such as plumbing, HVAC, electrical, appliance repair, cleaning, pest control, and landscaping, where jobs are scheduled, dispatched to a mobile technician, and closed out with an on-site invoice or payment. Its mobile-first design reflects how these teams actually work day to day.$q$, $q$It also fits businesses that are actively trying to modernize: companies moving off paper job tickets, generic calendars, or a patchwork of separate invoicing and payment apps. Owners who want visibility into technician schedules, job history, and revenue in one place tend to get the most value from adopting it.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very large, multi-division field service organizations with complex enterprise requirements, such as deep custom workflow logic, advanced multi-warehouse inventory, or bespoke integrations with legacy back-office systems, may find the platform's out-of-the-box structure limiting compared with heavier enterprise field service suites.$q$, $q$Extremely price-sensitive solo operators who only need basic scheduling or invoicing may find that the features they actually use don't justify the monthly cost once optional add-ons like payment processing fees or marketing tools are factored in. Simpler, cheaper single-purpose apps may serve very small operations better.$q$, $q$Businesses outside the home services mold, such as general contractors running long, multi-phase construction projects, retail operations needing point-of-sale hardware, or project-based consultancies, are also not the primary use case, since the product's workflows are built around dispatched, job-based service visits rather than long project management cycles.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Scheduling and dispatch sit at the center of the product, with a drag-and-drop calendar, technician availability tracking, and GPS-based routing so office staff can assign the right job to the right crew. A customer-facing online booking widget and automated appointment reminders help reduce no-shows and phone-tag scheduling.$q$, $q$On the money side, Housecall Pro handles estimates, invoicing, and in-app payment processing, letting technicians collect payment on-site by card or other digital methods and automatically sync the transaction back to the office. QuickBooks Online integration keeps bookkeeping aligned without duplicate data entry.$q$, $q$Beyond core operations, the platform includes customer relationship management with job history and communication logs, marketing tools such as automated review requests and email or postcard campaigns, price book and flat-rate pricing tools, and reporting dashboards that surface revenue, technician performance, and job profitability. Zapier and an open API extend it to other business tools.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$the-housecall-pro-experience$q$, $q$The Housecall Pro Experience$q$, 2, ARRAY[$q$New customers typically go through a guided onboarding process, importing existing customer lists and configuring pricing, teams, and notification settings before technicians start using the mobile app in the field. The web dashboard and mobile app share a consistent, straightforward interface aimed at non-technical office staff and busy technicians alike.$q$, $q$Support is delivered through in-app chat, phone support, and a self-serve help center, and Housecall Pro also runs community and educational content aimed at helping trades business owners grow, covering topics like pricing strategy, marketing, and team management alongside product how-tos.$q$, $q$In daily use, most feedback centers on how much friction it removes from scheduling, dispatch, and getting paid compared with manual processes, while the tradeoff owners weigh is a subscription cost structure with per-user pricing and optional paid add-ons that can add up as a team grows.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
