INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Contact and company management$q$, $q$Store unlimited contacts and companies with automatically enriched records, activity timelines, and custom properties.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Visual deal pipeline$q$, $q$Track opportunities through customizable, drag-and-drop stages with deal values, close dates, and forecasting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Email tracking and templates$q$, $q$See when prospects open or click emails, and send from a library of reusable, personalized templates.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Meeting scheduling$q$, $q$Share booking links that sync with reps' calendars so prospects can self-schedule meetings without back-and-forth.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Live chat and bots$q$, $q$Engage website visitors in real time or route conversations with simple, rule-based chatbots.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Reporting dashboards$q$, $q$Visualize pipeline health, activity, and team performance with prebuilt and customizable dashboards.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Workflow automation$q$, $q$Automate lead rotation, task creation, and follow-up reminders as deals and contacts change stage.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Gmail and Outlook integration$q$, $q$Log emails and calendar events automatically from a user's inbox without leaving their normal workflow.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$App Marketplace and API$q$, $q$Connect hundreds of third-party tools or build custom integrations against HubSpot's public API.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Mobile apps$q$, $q$Manage contacts, deals, and notifications on the go with native iOS and Android applications.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Free tier supports unlimited users and core CRM records with no time limit$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Clean, intuitive interface that requires little training to get started$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Deep integration with HubSpot's Marketing, Sales, Service, and Content Hubs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Large ecosystem of integrations, templates, and HubSpot Academy training$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Scales from a simple contact database up to enterprise-grade sales operations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Costs rise quickly once teams need paid Marketing, Sales, or Service Hub features$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Per-seat pricing plus contact tier limits can make budgeting unpredictable$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Advanced customization and reporting are gated behind Professional and Enterprise plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Onboarding fees apply to some paid plans, adding to upfront cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Can feel feature-heavy for teams that only need a lightweight contact list$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Is HubSpot CRM really free?$q$, $q$Yes. The core CRM, including contact and deal management for unlimited users, is free indefinitely. Paid upgrades exist for advanced marketing, sales, and service features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$How does HubSpot CRM differ from HubSpot's Marketing, Sales, and Service Hubs?$q$, $q$HubSpot CRM is the free underlying database of contacts, companies, and deals. Marketing, Sales, and Service Hub are paid product lines that add automation, advanced reporting, and specialized tools on top of that same CRM data.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Can HubSpot CRM integrate with other tools?$q$, $q$Yes. HubSpot offers a large App Marketplace with integrations for email, e-commerce, support, and finance tools, plus a public API for custom connections.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Is HubSpot CRM good for small businesses?$q$, $q$It is a popular choice for small businesses because the free tier covers essential contact and pipeline management without upfront cost, with room to add paid features as the business grows.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Does HubSpot CRM have a mobile app?$q$, $q$Yes, HubSpot offers native iOS and Android apps so sales and support teams can manage contacts, deals, and notifications away from their desks.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Centralizing a growing sales pipeline$q$, $q$Replace scattered spreadsheets with a shared, visual deal pipeline so every rep and manager can see deal status and forecasted revenue in one place.$q$, $q$Small business sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Capturing and qualifying inbound leads$q$, $q$Use free forms, live chat, and email tracking to capture website visitors as contacts and follow up before they go cold.$q$, $q$Marketing and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Managing multiple client accounts$q$, $q$Give each client a dedicated, organized contact and deal workspace, with the option to layer on Marketing or Service Hub for clients that need more.$q$, $q$Agencies and consultants$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Scaling into a full customer platform$q$, $q$Start on the free CRM and progressively add Marketing, Sales, Service, or Content Hub as headcount and complexity grow, without migrating data.$q$, $q$Scaling mid-market companies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Free CRM$q$, $q$$0$q$, $q$Free forever$q$, $q$["Unlimited users and contact records","Deal pipeline and task management","Email tracking and templates","Live chat and basic forms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Starter$q$, $q$From $20/month per seat$q$, $q$Monthly or annual$q$, $q$["Simple automation for follow-ups","Removes HubSpot branding","Basic reporting","Available across Marketing, Sales, and Service Hub"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Professional$q$, $q$Custom (varies by Hub)$q$, $q$Monthly or annual$q$, $q$["Advanced workflow automation","Custom reporting dashboards","Multiple deal pipelines and teams","A/B testing and smart content (Marketing Hub)"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Monthly or annual$q$, $q$["Advanced permissions and custom objects","Predictive lead scoring","Sandbox environments","Dedicated onboarding support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HubSpot CRM is the free customer relationship management platform at the core of HubSpot's broader suite of marketing, sales, service, and content tools. Launched as a no-cost entry point, it gives businesses a central place to store contacts and companies, track deals through a visual pipeline, and log every email, call, and meeting automatically without asking reps to do extra data entry.$q$, $q$Founded in 2006 in Cambridge, Massachusetts by Brian Halligan and Dharmesh Shah, HubSpot built its reputation on inbound marketing before expanding into a full customer platform spanning marketing, sales, service, and content management. HubSpot CRM sits underneath that platform, connecting to the paid Marketing Hub, Sales Hub, Service Hub, and Content Hub so teams can start free and add capability as they grow, rather than migrating to a new system later.$q$, $q$The product is aimed squarely at replacing spreadsheets and disconnected tools with one shared record of customer activity that sales, marketing, and support teams can all see. Because the core CRM is free for unlimited users, it has become a common first CRM for small teams, while its deep upgrade path also supports large sales and marketing organizations running on the same underlying contact and deal data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$who-hubspot-crm-is-for$q$, $q$Who HubSpot CRM Is For$q$, 2, ARRAY[$q$HubSpot CRM is well suited to small and mid-sized businesses that need a shared system for contacts, deals, and customer conversations but do not want to pay for software before proving it fits their process. Founders, sales reps, and support teams can be onboarded quickly because the free tier requires no procurement approval.$q$, $q$It also fits growing sales teams that want a visual, drag-and-drop pipeline instead of a spreadsheet, plus marketing teams that plan to eventually adopt HubSpot's paid Marketing Hub and want their contact data to live in the same place from day one. Agencies managing multiple client accounts often standardize on HubSpot CRM for this reason.$q$, $q$Larger organizations already invested in the HubSpot ecosystem, or companies choosing a platform they can scale into over several years, are strong candidates as well. Because the free CRM, paid Hubs, and app marketplace all share one data model, teams that expect to add marketing automation, help desk, or CMS tools later benefit from starting on HubSpot CRM early rather than reconciling separate systems down the road.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need only the most basic contact list with no plans to ever use email tracking, forms, or pipeline features may find dedicated, cheaper single-purpose tools simpler. HubSpot's broader ecosystem is designed to be grown into, and buyers who only want a lightweight address book may find the interface has more surface area than they need.$q$, $q$Budget-conscious teams should also be cautious once they outgrow the free tier: HubSpot's paid Starter, Professional, and Enterprise plans across Marketing, Sales, and Service Hub can become expensive quickly, especially with per-seat pricing, contact tier overages, and onboarding fees on higher plans. Companies expecting Salesforce-level customization at CRM-level pricing may be disappointed.$q$, $q$Highly specialized industries with regulatory or workflow needs that generic CRMs do not address well, or organizations already deeply invested in a competing platform such as Salesforce or Microsoft Dynamics, may find migration costs and workflow rebuilding outweigh the benefits of switching to HubSpot CRM, particularly if existing integrations and custom reports would need to be rebuilt from scratch.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, HubSpot CRM provides contact and company records, deal pipelines, and task management, all automatically populated from email, calendar, and form activity through browser and email integrations. Sales reps get email tracking and open notifications, meeting scheduling links, and a Gmail or Outlook integration that logs correspondence without manual entry, keeping every record current with minimal upkeep.$q$, $q$Marketing-adjacent features include basic email sending, live chat and simple chatbots, and web forms that feed directly into contact records, giving even free-tier users a light-touch way to capture and qualify leads before they need a full marketing automation platform. Reporting dashboards summarize pipeline health, deal velocity, and team activity, with more advanced custom reporting and attribution unlocked in paid tiers.$q$, $q$The CRM extends through HubSpot's App Marketplace, connecting to hundreds of third-party tools including e-commerce, accounting, and support platforms, and through a documented API for custom integrations. Workflow automation, custom properties, and permission controls scale from simple free-tier defaults up to complex, enterprise-grade configurations as a company upgrades into Sales Hub, Marketing Hub, or Service Hub.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$the-hubspot-crm-experience$q$, $q$The HubSpot CRM Experience$q$, 2, ARRAY[$q$Day to day, HubSpot CRM feels like a clean, modern web application built around records and boards rather than dense spreadsheets. Navigating between a contact, its associated company, and open deals is fast, and the drag-and-drop deal pipeline gives sales teams an at-a-glance view of what needs attention without extra configuration or a steep setup process.$q$, $q$New users are guided through setup with in-app prompts, sample data, and an extensive library of free HubSpot Academy courses and help documentation, which keeps the learning curve manageable even for teams without a dedicated CRM administrator. Mobile apps for iOS and Android let reps update deals, log calls, and check notifications away from their desks, so the pipeline stays current between office visits.$q$, $q$As teams add paid Hubs, the experience deepens rather than fragments: marketing emails, support tickets, and sales activity all surface on the same contact timeline, so anyone touching an account sees its full history in one place. That consistency is HubSpot CRM's biggest experiential strength, though it also means the interface can feel busier once multiple Hubs and their respective menus, settings, and reports are all active at once.$q$]::text[], 4);
